import React from 'react';
import { Box, CssBaseline, AppBar, Toolbar, Typography, Drawer, List, ListItem, IconButton } from '@mui/material';
import { BrowserRouter as Router, Route, Routes, Link, useNavigate } from 'react-router-dom';
import LogoutIcon from '@mui/icons-material/Logout';
import './Admin.css';

const drawerWidth = 250;

const Admin = ({ token }) => {
    const navigate = useNavigate();

    const handleLogout = () => {
        localStorage.removeItem('token');
        navigate('/login');
    };

    return (
        <div className="admin-panel">
            <CssBaseline />
            <Drawer
                variant="permanent"
                sx={{
                    width: drawerWidth,
                    '& .MuiDrawer-paper': { width: drawerWidth, boxSizing: 'border-box' },
                }}
                className="sidebar"
            >
                <div>
                    <h2>Admin Panel</h2>
                    <nav>
                        {['Dashboard', 'Countries', 'Clients', 'Tours', 'Bookings'].map((text) => (
                            <button key={text} className="nav-button" onClick={() => navigate(`/admin/${text.toLowerCase()}`)}>
                                {text}
                            </button>
                        ))}
                    </nav>
                </div>
            </Drawer>
            <Box className="main-content">
                <AppBar position="fixed" sx={{ bgcolor: '#2c3e50', width: `calc(100% - ${drawerWidth}px)` }}>
                    <Toolbar>
                        <Typography variant="h6" noWrap>
                            Admin Dashboard
                        </Typography>
                        <IconButton color="inherit" sx={{ marginLeft: 'auto' }} onClick={handleLogout}>
                            <LogoutIcon />
                        </IconButton>
                    </Toolbar>
                </AppBar>
                <Toolbar />
                <Routes>
                    <Route path="/admin/dashboard" element={<div>Dashboard Content</div>} />
                    <Route path="/admin/countries" element={<div>Manage Countries</div>} />
                    <Route path="/admin/clients" element={<div>Manage Clients</div>} />
                    <Route path="/admin/tours" element={<div>Manage Tours</div>} />
                    <Route path="/admin/bookings" element={<div>Manage Bookings</div>} />
                </Routes>
            </Box>
        </div>
    );
};

export default Admin;
